meta.script:
tailwind.config = {
    theme: {
        extend: {
            colors: {
                'echo-bg': '#E8E2D8',     // 米色背景
                'echo-gray': '#BFC6C4',   // 灰绿辅助
                'echo-green': '#6F8F72',  // 森林绿主色
                'echo-orange': '#F2A65A', // 暖橙强调
                'echo-dark': '#4A5553',   // 墨墨绿文字
            }
        }
    }
}

body.script:
const { createApp, ref, computed, onMounted } = Vue;

createApp({
    setup() {
        const view = ref('online');
        const inputUrl = ref('');
        const songs = ref([]);
        const allSelected = ref(false);
        const dragging = ref(false);
        const fileInput = ref(null);
        const tasks = ref([]);

        const selectedCount = computed(() => songs.value.filter(s => s.selected).length);

        const analyze = () => {
            if (!inputUrl.value) return;
            songs.value = [
                { id: 1, title: '平凡之路', artist: '朴树', size: '12.4 MB', selected: false },
                { id: 2, title: '那些花儿', artist: '朴树', size: '10.8 MB', selected: false },
                { id: 3, title: '白桦林', artist: '朴树', size: '9.2 MB', selected: false },
                { id: 4, title: '生如夏花', artist: '朴树', size: '11.5 MB', selected: false }
            ];
            setTimeout(() => lucide.createIcons(), 50);
        };

        const selectAll = () => {
            songs.value.forEach(s => s.selected = allSelected.value);
        };

        const triggerFile = () => fileInput.value.click();

        const handleFiles = (e) => {
            const files = Array.from(e.target.files);
            addTasks(files.map(f => f.name));
        };

        const handleDrop = (e) => {
            dragging.value = false;
            const files = Array.from(e.dataTransfer.files).filter(f => f.name.endsWith('.ncm'));
            addTasks(files.map(f => f.name));
        };

        const addTasks = (names) => {
            names.forEach(name => {
                const id = Math.random();
                const task = { id, name, progress: 0 };
                tasks.value.push(task);

                const interval = setInterval(() => {
                    task.progress += Math.floor(Math.random() * 10);
                    if (task.progress >= 100) {
                        task.progress = 100;
                        clearInterval(interval);
                        setTimeout(() => {
                            tasks.value = tasks.value.filter(t => t.id !== id);
                        }, 1500);
                    }
                }, 300);
            });
        };

        const downloadSelected = () => {
            const selected = songs.value.filter(s => s.selected);
            if (selected.length === 0) return;
            addTasks(selected.map(s => s.title + '.mp3'));
            songs.value = []; 
            allSelected.value = false;
        };

        onMounted(() => {
            lucide.createIcons();
        });

        return {
            view,
            inputUrl,
            songs,
            allSelected,
            dragging,
            fileInput,
            tasks,
            selectedCount,
            analyze,
            selectAll,
            triggerFile,
            handleFiles,
            handleDrop,
            downloadSelected
        };
    }
}).mount('#app');
